class Solution:
    def distanceTraveled(self, mainTank: int, additionalTank: int) -> int:
        distance = 0
        while mainTank > 0:
            # Determine how much fuel can be used in this step
            use = min(5, mainTank)
            distance += use * 10
            mainTank -= use

            # Check if we can transfer fuel from additional tank
            if mainTank >= 5 and additionalTank > 0:
                mainTank += 1
                additionalTank -= 1

        return distance
